import numpy as np

def compute_scale_symmetric(tensor: np.ndarray, n_bits: int) -> float:
    max_val = np.max(np.abs(tensor))
    q_max = 2 ** (n_bits - 1) - 1
    return float(max_val / q_max)

def quantize_symmetric(tensor: np.ndarray, scale: float, n_bits: int) -> np.ndarray:
    q_min = -(2 ** (n_bits - 1))
    q_max = 2 ** (n_bits - 1) - 1
    q = np.round(tensor / scale)
    return np.clip(q, q_min, q_max).astype(np.int32)

def dequantize_symmetric(q_tensor: np.ndarray, scale: float) -> np.ndarray:
    return q_tensor.astype(np.float32) * scale

pytorch_solution_code:
import torch

def compute_scale_symmetric(tensor: torch.Tensor, n_bits: int) -> float:
    max_val = tensor.abs().max().item()
    q_max = 2 ** (n_bits - 1) - 1
    return max_val / q_max

def quantize_symmetric(tensor: torch.Tensor, scale: float, n_bits: int) -> torch.Tensor:
    q_min = -(2 ** (n_bits - 1))
    q_max = 2 ** (n_bits - 1) - 1
    q = torch.round(tensor / scale)
    return torch.clamp(q, q_min, q_max).to(torch.int32)

def dequantize_symmetric(q_tensor: torch.Tensor, scale: float) -> torch.Tensor:
    return q_tensor.float() * scale
